let details=document.querySelectorAll("details");details&&details.forEach(function(e){[e.querySelector(".close-dropdown")].forEach(function(e){console.log("toggle: "+e),e&&e.addEventListener("click",l=>{e.closest("details[open]").removeAttribute("open")})})});let dialog=document.querySelectorAll("dialog");dialog&&dialog.forEach(function(e){[e.querySelector(".close-dialog")].forEach(function(e){console.log("toggle: "+e),e&&e.addEventListener("click",l=>{e.closest("dialog").close()})})});